-- Step 3: Update permission rows to point at new i18n IDs.
UPDATE permission AS p SET
    name_i18n_id = u.name_i18n_id,
    description_i18n_id = u.desc_i18n_id
FROM (VALUES
    ('00000000-0000-0004-0001-000000000101'::uuid, '00000000-0000-0000-0012-000000001000'::uuid, '00000000-0000-0000-0012-000000001001'::uuid) -- DENY_ALL,
